class TreeNode:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def search_bst(root, key):
    """Search for key in BST, return node if found"""
    # Base case: root is null or key is at root
    if root is None or root.key == key:
        return root

    # Key is greater than root's key
    if key < root.key:
        return search_bst(root.left, key)

    # Key is smaller than root's key
    return search_bst(root.right, key)

# Iterative version
def search_bst_iterative(root, key):
    while root is not None and key != root.key:
        if key < root.key:
            root = root.left
        else:
            root = root.right
    return root

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node* left;
    struct Node* right;
};

struct Node* newNode(int data) {
    struct Node* node = (struct Node*)malloc(sizeof(struct Node));
    node->data = data;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Preorder
void preorder(struct Node* node) {
    if (node == NULL) return;
    printf("%d ", node->data);
    preorder(node->left);
    preorder(node->right);
}

// Inorder
void inorder(struct Node* node) {
    if (node == NULL) return;
    inorder(node->left);
    printf("%d ", node->data);
    inorder(node->right);
}

// Postorder
void postorder(struct Node* node) {
    if (node == NULL) return;
    postorder(node->left);
    postorder(node->right);
    printf("%d ", node->data);
}

int main() {
    struct Node* root = newNode(1);
    root->left = newNode(2);
    root->right = newNode(3);
    root->left->left = newNode(4);
    root->left->right = newNode(5);

    printf("Preorder: "); preorder(root);   // 1 2 4 5 3
    printf("\nInorder: "); inorder(root);    // 4 2 5 1 3
    printf("\nPostorder: "); postorder(root); // 4 5 2 3 1
    return 0;
}
